const assert = require("node:assert/strict");
const fs = require("node:fs");
const path = require("node:path");
const vm = require("node:vm");

function run(name, fn) {
  try {
    fn();
    console.log(`ok - ${name}`);
  } catch (error) {
    console.error(`not ok - ${name}`);
    throw error;
  }
}

function plain(value) {
  return JSON.parse(JSON.stringify(value));
}

function loadCore() {
  const html = fs.readFileSync(path.join(__dirname, "index.html"), "utf8");
  const match = html.match(
    /\/\* pocketledger-core-start \*\/([\s\S]*?)\/\* pocketledger-core-end \*\//
  );

  assert.ok(match, "index.html exposes the PocketLedger core block");

  const sandbox = { console, window: {} };
  vm.createContext(sandbox);
  vm.runInContext(match[1], sandbox);

  return sandbox.window.PocketLedgerCore;
}

run("normalizes EUR amount input to integer cents", () => {
  const core = loadCore();

  assert.equal(core.parseAmountToCents("12,34"), 1234);
  assert.equal(core.parseAmountToCents("12.3"), 1230);
  assert.throws(() => core.parseAmountToCents("0"), /greater than zero/);
});

run("totals only expenses from the current month", () => {
  const core = loadCore();
  const now = new Date(2026, 6, 8);
  const expenses = [
    { amountCents: 1000, date: "2026-07-01" },
    { amountCents: 2500, date: "2026-06-30" },
    { amountCents: 750, date: "2026-07-31" },
  ];

  assert.equal(core.getCurrentMonthTotalCents(expenses, now), 1750);
});

run("adds, deletes, saves, and loads expenses without dependencies", () => {
  const core = loadCore();
  const storageState = {};
  const storage = {
    getItem(key) {
      return Object.prototype.hasOwnProperty.call(storageState, key)
        ? storageState[key]
        : null;
    },
    setItem(key, value) {
      storageState[key] = value;
    },
  };

  const expenses = core.addExpense(
    [],
    {
      amount: "5",
      category: "Coffee",
      date: "2026-07-08",
      note: "flat white",
    },
    () => "expense-1"
  );

  assert.deepEqual(plain(expenses), [
    {
      id: "expense-1",
      amountCents: 500,
      category: "Coffee",
      date: "2026-07-08",
      note: "flat white",
    },
  ]);

  core.saveExpenses(storage, expenses);
  assert.deepEqual(plain(core.loadExpenses(storage)), plain(expenses));
  assert.deepEqual(plain(core.deleteExpense(expenses, "expense-1")), []);
});

run("exports all expenses as CSV with safe values", () => {
  const core = loadCore();
  const expenses = [
    {
      id: "expense-1",
      amountCents: 1234,
      category: "Groceries, snacks",
      date: "2026-07-08",
      note: "bread \"daily\"",
    },
    {
      id: "expense-2",
      amountCents: 500,
      category: "Dining",
      date: "2026-07-07",
      note: "line one\nline two",
    },
  ];

  assert.equal(
    core.expensesToCsv(expenses),
    [
      "date,category,note,amount_eur",
      "2026-07-08,\"Groceries, snacks\",\"bread \"\"daily\"\"\",12.34",
      "2026-07-07,Dining,\"line one line two\",5.00",
    ].join("\r\n")
  );
});
run("renders a CSV export button", () => {
  const html = fs.readFileSync(path.join(__dirname, "index.html"), "utf8");

  assert.match(html, /id="export-csv"/);
  assert.match(html, />\s*Export CSV\s*</);
});

